-- Seed RICH content pour PharmaCi (ADW-2026-001) — version complète mockup-driven
-- À appliquer APRÈS seed_pe_fake_pharmaci.sql (qui crée la base structure)
-- Reproduit le contenu détaillé du mockup PE_experience_complete.html pour les 12 sections.
--
-- Usage : docker exec -i supabase_db_<ref> psql -U postgres -d postgres < seed_pe_pharmaci_rich.sql

DO $$
DECLARE
  v_deal_id UUID;
  v_pre_v UUID;
  v_ic1_v UUID;
BEGIN
  SELECT id INTO v_deal_id FROM pe_deals WHERE deal_ref = 'ADW-2026-001';
  IF v_deal_id IS NULL THEN
    RAISE EXCEPTION 'Deal ADW-2026-001 introuvable. Run seed_pe_fake_pharmaci.sql d''abord.';
  END IF;

  SELECT mv.id INTO v_pre_v FROM memo_versions mv
    JOIN investment_memos im ON im.id = mv.memo_id
    WHERE im.deal_id = v_deal_id AND mv.stage = 'pre_screening';
  SELECT mv.id INTO v_ic1_v FROM memo_versions mv
    JOIN investment_memos im ON im.id = mv.memo_id
    WHERE im.deal_id = v_deal_id AND mv.stage = 'note_ic1';

  IF v_pre_v IS NULL OR v_ic1_v IS NULL THEN
    RAISE EXCEPTION 'Versions pre_screening_v1 ou note_ic1_v1 introuvables. Run seed_pe_fake_pharmaci.sql d''abord.';
  END IF;

  -- executive_summary
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"data_par": "S. Koné (Analyste)", "redige_par": "K. N''Guessan (MD)", "review_par": null, "score_memo": 68, "version_note": "Pré-due diligence. Les données non vérifiées par un tiers sont signalées [non vérifié DD]. La version IC finale intégrera les résultats de la DD externe.", "auto_gen_note": "Ce résumé est auto-généré à partir des 11 autres sections. Régénéré à chaque validation de section.", "version_label": "IC1 (draft)", "validations_im": 4, "validations_md": 2, "last_generated_at": "16 avr."}, "footer": {"score_memo": 68, "sections_total": 12, "validations_im": 4, "validations_md": 2, "auto_gen_summary": "Ce résumé est auto-généré à partir des 11 autres sections. Il est régénéré à chaque validation de section.", "last_generated_at": "16 avr.", "sections_redigees": 12}, "kpis_bandeau": [{"hint": "CAGR 18% · 3 ans", "label": "CA 2025", "value": "2.82 Mds", "hint_color": "ok"}, {"hint": "Marge 10.6% · méd. 12%", "label": "EBITDA retraité", "value": "300M", "hint_color": "warning", "value_color": "warning"}, {"hint": "Q3 · méd. 28%", "label": "Marge brute", "value": "32%", "hint_color": "ok"}, {"hint": "seuil <2x", "label": "Dette nette / EBITDA", "value": "0.88x", "hint_color": "ok", "value_color": "ok"}, {"hint": "Equity pure", "label": "Ticket", "value": "4.2M EUR"}, {"hint": "8-10x EBITDA", "label": "Pre-money", "value": "10-14M"}, {"hint": "IRR 22% · 5 ans", "label": "MOIC base", "value": "2.8x", "hint_color": "info", "value_color": "ok"}], "presentation": {"heading": "Présentation de la cible", "paragraphs": ["PharmaCi Industries SA est un producteur ivoirien de médicaments génériques certifié BPF UEMOA, fondé en 2012 par Amidou Kouassi (pharmacien, ex-Cipharm) et basé à Yopougon (Abidjan). SARL au capital de 100M FCFA. L''entreprise emploie 127 personnes et exploite une usine de 2 400 m² certifiée BPF depuis 2019 (investissement de 280M FCFA). Elle produit 42 références de génériques (antalgiques, antibiotiques, antipaludéens, antihypertenseurs) sous formes sèches (70%), liquides (25%) et semi-solides (5%), distribuées via un double canal : appels d''offres hospitaliers publics PSP (60% du CA, marge contribution 32%) et réseau de 120 pharmacies d''officine privées via 3 grossistes-répartiteurs (40% du CA, marge 52%). [entretien DG 08/04 · visite site 11/04 · liasses SYSCOHADA 2023-2025]", "PharmaCi opère sur le segment de la production locale de génériques certifiés BPF en Afrique de l''Ouest — un sous-marché de 360-430M USD (15-18% d''un marché pharma total de 2.4 Mds USD) en croissance structurelle de 8-10% par an. Cette croissance est portée par trois mégatrends irréversibles : la démographie UEMOA (+2.7%/an), l''urbanisation (45%→52% d''ici 2030) et l''extension de la couverture maladie universelle (CI : 38%→60% en 2030 · SN : 47%). Le marché est protégé par la certification BPF UEMOA (barrière 200-400M FCFA, 18-24 mois) et la Directive UEMOA 2023 (+15% prix AO publics aux producteurs locaux certifiés). [IFC Pharma Africa 2024 · Directive UEMOA n°01/2023/CM]"]}, "deal_breakers": {"intro": "Deal breakers identifiés :", "items": ["Concentration client >70% après cartographie DD", "EBITDA retraité <8% après clarification rémunération DD"], "conclusion": "Si l''un des deux se matérialise → la recommandation passe de Go conditionnel à Hold et le deal ne va pas en comité IC1."}, "recommendation": {"color": "green", "heading": "Recommandation formelle", "summary": "Deal compatible avec la thèse mid-market santé du fonds sur 5 des 6 critères (secteur ✓, ticket ✓, géo ✓, CA min ✓, EBITDA positif ✓, états financiers certifiés ⚠ partiel — certifié 2025 uniquement avec réserves). Profil financier au-dessus de la médiane sectorielle sur marge brute (32% vs 28%), croissance (18% vs 10%), endettement (0.88x vs 1.5x). En dessous de la médiane sur EBITDA retraité (10.6% vs 12%) — écart explicable par retraitement rémun. dirigeant.", "verdict": "go_conditionnel", "conditions": [{"n": 1, "text": "Obtenir les liasses 2024 certifiées par le CAC (Cabinet Diallo & Associés). Délai estimé : 4-6 semaines."}, {"n": 2, "text": "Clarifier la politique de rémunération du dirigeant pour fiabiliser l''EBITDA retraité (estimation analyste : rémun. DG 100M + charges perso 20M)."}, {"n": 3, "text": "Cartographier les 10 premiers clients avec poids respectif, nature contractuelle (AO ponctuel vs cadre), et historique de renouvellement."}], "score_brut": 97, "score_esono": 74, "score_section": "Score d''adéquation thèse : 83%.", "verdict_label": "GO CONDITIONNEL — conviction modérée", "score_threshold": 65, "conditions_intro": "Trois conditions préalables au passage en IC1 :"}, "thesis_5_points": {"items": [{"n": 1, "body": "Certification BPF UEMOA = oligopole de fait (3 producteurs en CI : PharmaCi, Pharmivoire, Cipharm). Barrière en 3 couches : certification BPF (200-400M FCFA, 18-24 mois) + 42 agréments par molécule construits sur 12 ans + historique 2+ ans exigé en AO publics. Directive UEMOA 2023 ajoute +15% prix AO. [Directive UEMOA n°01/2023/CM]", "lead": "Moat réglementaire durable et auto-renforçant."}, {"n": 2, "body": "CAGR CA 18% sur 3 ans (vs Pharmivoire +6%, Cipharm +9%). 3 leviers : (a) capacité existante à 62%, +38% sans CAPEX ; (b) nouvelle ligne (financement, fournisseur Sejong Pharmatech identifié) double la capacité à 100M unités/an ; (c) expansion SN (réplication exacte modèle BPF UEMOA). Pipeline 8 AO en soumission dont 3 quasi-certains. Use of proceeds 85% CAPEX productif.", "lead": "Croissance visible, finançable et quantifiable."}, {"n": 3, "body": "Pharmacie générique = contra-cyclique. Impact direct ODD 3 (2M+ patients/an via AO publics), ODD 8 (127+30 emplois post-invest), ODD 9 (production locale, substitution import). Profil recherché par DFI (Proparco, BII, IFC, FMO) qui co-investissent avec PE. Éligibilité 2X Criteria post-structuration gouvernance.", "lead": "Secteur défensif à impact avec profil DFI attractif."}, {"n": 4, "body": "Base case MOIC 2.8x / IRR 22% sur 5 ans (croiss. CA 15%/an conservateur, exit 8x EBITDA médiane secteur). Bear case MOIC 1.8x / IRR 12% (au-dessus du seuil fonds 1.5x). Bull case 4.1x / 33% (expansion SN+CI+BF, 22% croiss., exit 10x). Convergence DCF 12.4M / multiples 11.8M (écart 5%) → robustesse 10-14M EUR pre-money.", "lead": "Profil de rendement attractif avec protection du capital."}, {"n": 5, "body": "M. Kouassi (72%, DG, 14 ans pharma dont 3 ans chez Cipharm) reste majoritaire. Ne cherche pas exit — veut accélérer croissance. Management pool 10% (Dr. Traoré, M. Diarra) introduit en 2020 aligne intérêts. Le fondateur a validé en entretien 6 conditions de structuration post-investissement (CA 3 membres, DAF, double signature, AG, séparation comptes, assurance homme-clé). Coopération proactive rare dans PME familiales UEMOA.", "lead": "Management fondateur aligné et coopératif."}], "heading": "Thèse d''investissement en 5 points"}, "monitoring_points": ["BFR en hausse (14% → 17.4% du CA en 3 ans, principalement allongement délais PSP)", "Convention réglementée bail commercial DG/SCI Kouassi (42M FCFA/an, dans la fourchette marché mais à auditer en DD)"], "red_flags_synthesis": [{"body": "Seuil d''alerte : 40%. Les 3 clients sont des AO hospitaliers PSP. Atténuation possible si AO récurrents — à vérifier en DD par cartographie détaillée. Si concentration réelle >70% après cartographie → deal breaker, recommandation passe en Hold.", "title": "Concentration client 62% top 3", "severity": "Critical", "penalty_pts": -15, "penalty_dimension": "Gouvernance"}, {"body": "Masse salariale / CA = 8.75% vs médiane secteur 12%. Écart cohérent avec rémun. non déclarée 80-120M FCFA. Retraitement retenu : 100M (milieu de fourchette) + charges perso 20M = 300M EBITDA retraité (marge 10.6%). Si EBITDA retraité <8% après clarification DD → deal breaker.", "title": "EBITDA sans rémunération dirigeant identifiée", "severity": "High", "penalty_pts": -8, "penalty_dimension": "Finance"}, {"body": "Pas de CA formalisé, DG cumule 4 fonctions (DG + DAF + relation clients + signataire bancaire unique), PV AG 2024-2025 absents. Corrigeable en 100 jours post-closing avec plan de structuration validé par fondateur.", "title": "Gouvernance centralisée", "severity": "High", "penalty_pts": -5, "penalty_dimension": "Gouvernance"}]}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'executive_summary';

  -- shareholding_governance
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "version_note": "Pré-due diligence. Données non vérifiées signalées. La version IC finale intégrera les résultats de la DD externe.", "version_label": "IC1 (draft)"}, "footer": {"date": "10 avr.", "sources": "Statuts, PV AG 2023, RCCM, entretien DG", "redige_par": "S. Koné", "review_comment": "Demander le détail du mécanisme d''attribution du management pool en 2020 — potentielle irrégularité article 373 AUSCGIE."}, "cap_table": {"rows": [{"bold": true, "role": "Fondateur, DG opérationnel. Ex-Cipharm (3 ans), ex-CHU Cocody (4 ans). Cumule DG + DAF + signataire bancaire unique.", "type": "Ordinaire", "entree": "2012", "percent": 72, "actionnaire": "Amidou Kouassi"}, {"role": "Famille. Pas de rôle opérationnel identifié dans l''entreprise. Présente aux AG (quand elles ont lieu).", "type": "Ordinaire", "entree": "2012", "percent": 18, "actionnaire": "Fatou Kouassi (épouse)"}, {"role": "Dr. B. Traoré (Dir. Production), M. Diarra (Dir. Commercial), Resp. logistique. Mécanisme d''attribution non documenté — à clarifier en DD.", "type": "Ordinaire", "entree": "2020", "percent": 10, "actionnaire": "Management pool (3 pers.)"}], "notes": ["Structure familiale classique des PME industrielles UEMOA. 90% des parts sont détenues par le couple fondateur (72% + 18%). Pas d''investisseur institutionnel au capital. L''introduction du management pool (10%) en 2020 est un signal positif d''alignement d''intérêts, mais le mécanisme d''attribution n''est pas documenté dans les statuts consultés — potentielle irrégularité OHADA à vérifier en DD juridique.", "Historique des modifications du capital : capital social initial 10M FCFA en 2012. Augmentation 2015 (apport numéraire 50M par fondateur). Augmentation 2020 (incorporation réserves + cession 10% au management pool). Capital social actuel : 100M FCFA. Aucun coup d''accordéon, aucune dilution externe historique."]}, "red_flags": [{"body": "Pas de CA formalisé, cumul DG/DAF, seul signataire bancaire, pas de PV AG 2024-2025. Pénalité -5 pts. Détection automatique knowledge_risk_factors. Corrigeable en 100 jours post-closing avec le plan de structuration validé par fondateur.", "title": "Gouvernance centralisée", "severity": "High"}, {"body": "1 personne = DG + DAF + seul contact clients majeurs + seul signataire bancaire. Pénalité -10 pts. Si M. Kouassi est indisponible, la continuité opérationnelle est compromise — le suivi de trésorerie serait le premier point de blocage.", "title": "Homme-clé", "severity": "High"}], "governance": {"ag": "le dernier PV d''AG identifié date de 2023 (approbation comptes 2022). L''obligation légale d''AG annuelle (article 337 AUSCGIE) n''est pas strictement respectée — les AG 2024 et 2025 n''ont pas eu lieu ou n''ont pas été documentées. Point à régulariser en 100 jours post-investissement.", "ca": "pas de CA formalisé. La SARL est gérée par un gérant unique (M. Kouassi, article 323 AUSCGIE). Décisions stratégiques (investissements, embauches, contrats majeurs) prises unilatéralement. Fonctionnement courant pour les SARL familiales UEMOA pré-investissement — ne reflète pas un refus mais un manque de besoin avant l''arrivée d''un investisseur institutionnel.", "cac": "Cabinet Diallo & Associés (nommé en 2024). Certification 2025 obtenue avec réserves : (1) mélange constaté entre comptes personnels et professionnels du DG, (2) absence de procédure formalisée d''engagement des dépenses. La nomination d''un CAC est un signal positif de formalisation progressive.", "controle_interne": "aucun dispositif formalisé. Le DG est seul signataire bancaire sur les 2 comptes (NSIA Banque). Pas de procédure d''engagement des dépenses. Le suivi de trésorerie est fait par le DG sur un fichier Excel personnel — non partagé, non sauvegardé, non auditable. Priorité n°1 de la structuration post-investissement."}, "conventions": [{"body": "PharmaCi SARL loue ses locaux de production (2 400 m² à Yopougon, zone Cosrou) à la SCI Kouassi (gérée par M. Kouassi). Loyer 3.5M FCFA/mois (42M/an = 1.5% du CA 2025). Dans la fourchette marché pour zone industrielle Yopougon (estimation 30-50M FCFA/an). Conformité prix à vérifier formellement en DD par expert immobilier indépendant.", "title": "Convention 1 — Bail commercial (confirmée)", "severity": "Medium"}, {"body": "Véhicule Toyota Land Cruiser immatriculé au nom de la SCI Kouassi apparaît dans les charges d''exploitation de PharmaCi (amortissement + carburant ~8M FCFA/an). Usage personnel vs professionnel non documenté. Point mineur en montant mais à clarifier en DD pour la transparence.", "title": "Convention 2 — Véhicule de fonction (suspectée)", "severity": "Medium"}], "structuration_plan": {"intro": "Le fondateur a validé les 6 points suivants lors de l''entretien du 8 avril :", "items": [{"body": "100 jours : DG + 1 siège investisseur + 1 indépendant (pharmacien senior ou dirigeant industriel).", "title": "Formalisation CA 3 membres"}, {"body": "Budget 15M FCFA/an, profil 8+ ans SYSCOHADA, ex-Big 4 Abidjan.", "title": "Recrutement DAF"}, {"body": "DG + DAF pour tout engagement > 5M FCFA.", "title": "Double signature bancaire"}, {"body": "PV 2024 et 2025 à produire.", "title": "Régularisation AG"}, {"body": "Du DG.", "title": "Séparation comptes perso/pro"}, {"body": "Sur le DG dans les 100 jours.", "title": "Assurance homme-clé"}]}}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'shareholding_governance';

  -- top_management
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "version_note": "Pré-due diligence. Données non vérifiées signalées. La version IC finale intégrera les résultats de la DD externe.", "version_label": "IC1 (draft)"}, "footer": {"date": "11 avr. après visite site Yopougon", "sources": "Pitch deck, entretien DG, visite site, organigramme informel", "redige_par": "S. Koné"}, "red_flags": [{"body": "Si M. Kouassi est indisponible, Dr. Traoré assure la continuité production et M. Diarra les relations clients. La trésorerie serait le point de blocage — d''où l''urgence du recrutement DAF. Assurance homme-clé à souscrire dans les 100 jours. Plan de succession à formaliser dans les 6 mois. Par ailleurs, Dr. Traoré est lui-même un homme-clé production (seul certifié inspecteur BPF) — un plan de succession interne (formation d''un adjoint) est nécessaire. Pénalité -10 pts.", "title": "Homme-clé", "severity": "High"}], "postes_vacants": [{"body": "Poste inexistant. Comptabilité externalisée au Cabinet Diallo qui produit les liasses annuelles avec 3-4 mois de retard. Suivi trésorerie quotidien par le DG sur Excel personnel — non partagé, non sauvegardé, non auditable. Condition sine qua non de la structuration. Sans DAF : pas de reporting fiable, pas de contrôle des flux, pas de prévisionnel. Profil : 8+ ans SYSCOHADA, idéalement ex-Big 4 Abidjan (Deloitte, PwC, EY).", "delay": "100 jours post-closing", "title": "DAF", "budget": "15M FCFA/an", "priority": 1}, {"body": "127 employés gérés par le DG et une assistante. Contrats à jour (CNPS vérifiée 2024-2025), mais pas de grille salariale formalisée, pas de politique rémunération variable, pas d''entretiens annuels, pas de plan de formation. Masse salariale 245M FCFA (8.75% du CA) vs médiane secteur 12% — l''écart est essentiellement la rémun. non déclarée du DG.", "delay": "6 mois", "title": "DRH", "budget": "10M FCFA/an", "priority": 2}, {"body": "L''expansion Sénégal (25% du use of proceeds) nécessite un directeur pays dédié pour piloter la certification BPF SN, identifier les AO hospitaliers, gérer les relations PSP Dakar. Profil : pharmacien industriel avec réseau hospitalier public SN. M. Diarra (ex-Sanofi, réseau SN) assure l''intérim.", "delay": "12 mois", "title": "Dir. pays Sénégal", "budget": "15-20M FCFA/an", "priority": 3}], "equipe_dirigeante": {"rows": [{"exp": "14 ans", "name": "A. Kouassi", "poste": "DG / Fondateur", "profil_eval": "Pharmacien diplômé Université Cocody (2008). 4 ans pharmacien hospitalier CHU Cocody — c''est là qu''il a compris le mécanisme des AO publics. 3 ans responsable production chez Cipharm — connaissance intime de la production pharma industrielle. Fonde PharmaCi en 2012 avec 10M FCFA de fonds propres. Pilote l''obtention BPF UEMOA en 2019. Profil technique + commercial + entrepreneurial rare. Cumule DG + DAF + relation clients + signataire bancaire — risque homme-clé à traiter en priorité."}, {"exp": "8 ans", "name": "Dr. B. Traoré", "poste": "Dir. Production", "profil_eval": "Pharmacien industriel, Université de Bamako (2014). Certifié inspecteur BPF par l''autorité de régulation UEMOA. Responsable du dossier de certification BPF 2019 — compétence rare et critique. Gère 12 ouvriers production + 4 techniciens contrôle qualité. Homme clé côté production — sans lui, la certification BPF serait en risque. Pas de successeur identifié — plan de succession à formaliser."}, {"exp": "6 ans", "name": "M. Diarra", "poste": "Dir. Commercial", "profil_eval": "Ex-commercial Sanofi Afrique de l''Ouest (2012-2020), couverture CI + SN + ML. Réseau hospitalier public construit sur 8 ans chez Sanofi — connaît personnellement les pharmaciens hospitaliers et les responsables PSP. Rejoint PharmaCi en 2020. A triplé le nombre d''AO remportés en 3 ans (de 4 à 12). Son réseau au Sénégal est l''atout clé pour l''expansion — il connaît déjà les décideurs de la PSP Dakar."}], "synthesis": "Les 3 compétences critiques du secteur pharma sont couvertes — vision stratégique + connaissance marché (DG, ex-Cipharm + ex-CHU), production industrielle certifiée (Dr. Traoré, certifié BPF), réseau commercial hospitalier public (M. Diarra, ex-Sanofi). Le management pool (10% du capital) introduit en 2020 aligne leurs intérêts. Les 3 cadres clés sont en poste depuis 5-6 ans — pas de turnover récent."}, "capacite_absorption": {"evaluation": "Insuffisante en l''état, mais corrigeable avec le plan de recrutement.", "paragraphs": ["L''équipe actuelle (3 cadres dirigeants + 127 employés) peut absorber la croissance organique sur la ligne existante (+38% de capacité) mais pas simultanément l''installation de la nouvelle ligne ET l''expansion Sénégal. Le budget recrutement total (DAF 15M + DRH 10M + Dir. SN 15-20M = 40-45M FCFA/an) est intégré dans les projections de charges (§7) et dans le plan de value creation (§10). Le fondateur est conscient de ce besoin et l''a identifié lui-même lors de l''entretien."]}}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'top_management';

  -- services
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "version_note": "Données issues de la visite site du 11/04 et de l''entretien DG du 08/04. Volumes et taux d''utilisation déclaratifs (non vérifié DD).", "version_label": "IC1 (draft)"}, "footer": {"date": "11 avr. (visite site Yopougon)", "sources": "Visite site 11/04, entretien DG 08/04, catalogue produits, statuts, pitch deck", "redige_par": "S. Koné"}, "moat_bpf": {"intro": "Le moat compétitif de PharmaCi est constitué de 3 couches cumulatives qui rendent l''entrée d''un nouveau concurrent extrêmement difficile :", "layers": [{"body": "200-400M FCFA d''investissement et 18-24 mois pour obtenir la certification. Inspection rigoureuse par l''ANRP. Seuls 3 producteurs en CI la détiennent. Un quatrième (Pharma Ivoire Générique 2020) a échoué à la première inspection 2022 et n''a pas retentée.", "title": "Certification BPF UEMOA"}, {"body": "Construits sur 12 ans. Chaque AMM = 6-12 mois d''enregistrement ANRP. Un concurrent certifié BPF doit attendre 3-5 ans pour atteindre la même couverture de gamme.", "title": "42 agréments de mise sur le marché"}, {"body": "Exigence des AO publics hospitaliers. Un nouveau producteur certifié BPF doit accumuler 2 ans de ventes privées avant de pouvoir soumissionner sur les AO publics — soit la totalité du marché public hospitalier inaccessible pendant 2 ans minimum.", "title": "Historique de fourniture 2+ ans"}]}, "distribution": {"paragraphs": ["Canal public — AO hospitaliers PSP (60% du CA, marge contribution 32%) : la PSP (Pharmacie de la Santé Publique) centralise les achats des hôpitaux publics et établissements sanitaires. PharmaCi soumissionne aux AO et bénéficie de la Directive UEMOA 2023 (+15% prix). 12 AO actifs en 2025 (vs 4 en 2022). Délais paiement contractuels 30j, effectifs 90-120j (point d''attention BFR cf. §8).", "Canal privé — Pharmacies d''officine (40% du CA, marge 52%) : distribution via 3 grossistes-répartiteurs (Ubipharm, Laborex, COPHARMED) qui couvrent 120 pharmacies. Prix de vente 30-40% inférieurs aux princeps importés. Délais paiement 15-30j (canal beaucoup plus sain financièrement). Plan de croissance : extension à 200 pharmacies en 12 mois post-investissement (recrutement 2 commerciaux)."]}, "supply_chain": {"paragraphs": ["API (62% du coût de revient) : 3 fournisseurs principaux en Inde — Cipla (Mumbai, 40% des achats), Dr. Reddy''s (Hyderabad, 35%), Aurobindo (Hyderabad, 25%). Délais livraison 30-45j. Stock actuel 1 mois — passage à 2 mois avec le BFR du financement (buffer tensions mer Rouge depuis 2024). Tensions logistiques mer Rouge 2024 : hausse 12% prix API absorbée (cf. analyse §6). Plan : passage achats spot → contrats annuels (-5% prix, +45M FCFA/an de marge).", "Excipients (14% du coût) : approvisionnement Chine (60%) et fournisseurs locaux UEMOA (40%). Pas de tension identifiée. Conditionnement (9% du coût) : majoritairement local (cartons Côte d''Ivoire, blisters importés)."]}, "gamme_produits": {"rows": [{"marge": "30%", "pct_ca": "35%", "famille": "Antalgiques / anti-inflammatoires", "molecules": "Paracétamol 500mg, ibuprofène 400mg, diclofénac 50mg. Fort volume, marge modérée. Concurrence importations indiennes sur canal privé.", "references": "14"}, {"marge": "34%", "pct_ca": "25%", "famille": "Antibiotiques courants", "molecules": "Amoxicilline 500mg, ciprofloxacine 500mg, métronidazole 250mg. Demande stable, marge supérieure. Forte demande AO hospitaliers.", "references": "10"}, {"marge": "36%", "pct_ca": "25%", "famille": "Antipaludéens", "molecules": "Artéméther-luméfantrine, artésunate-amodiaquine. Meilleure marge. Demande saisonnière (pic juin-oct). Segment prioritaire expansion SN.", "references": "8"}, {"marge": "32%", "pct_ca": "15%", "famille": "Antihypertenseurs", "molecules": "Amlodipine 5/10mg, losartan 50mg, hydrochlorothiazide 25mg. Croissance rapide (+25%/an) maladies chroniques urbaines. Pipeline 4 nouvelles réf. ANRP.", "references": "10"}], "formes_galeniques": "Formes galéniques : sèches (comprimés, gélules) = 70% du volume — cœur de métier le plus rentable. Liquides (sirops, suspensions) = 25% — marge inférieure mais demande hospitalière pédiatrique forte. Semi-solides (pommades) = 5% — volume marginal mais complétude de gamme nécessaire pour AO multi-lots."}, "nature_activite": "PharmaCi est un producteur de médicaments génériques certifié BPF UEMOA. L''activité couvre la totalité de la chaîne, de l''achat de principes actifs (API) en Inde jusqu''à la distribution aux hôpitaux publics et pharmacies d''officine en Côte d''Ivoire. Pas de R&D — production de molécules dont le brevet a expiré, sous formes galéniques standardisées, aux normes BPF UEMOA. Modèle industriel de commodités pharmaceutiques à forte barrière réglementaire.", "site_production": "Usine de 2 400 m² à Yopougon (Cosrou, zone industrielle Abidjan), certifiée BPF UEMOA depuis 2019 (investissement 280M FCFA). Capacité installée 50M unités/an en 1 poste (peut passer à 100M en 2 postes). Salle blanche classifiée ISO 8 (zone production) et ISO 7 (remplissage liquides). Équipements clés : presse à comprimés Pharmatech (capacité 30K/h), ligne conditionnement primaire Bosch, blistering Marchesini, contrôle qualité HPLC Agilent + dissolution Distek. Laboratoire QC interne avec 4 techniciens certifiés. Visite site analyste 11/04 — installations propres et bien tenues.", "capacite_production": {"kpis": [{"label": "Capacité installée", "value": "50M unités/an"}, {"label": "Production 2025", "value": "31M unités"}, {"label": "Taux utilisation", "value": "62%"}, {"label": "Potentiel 2 postes", "value": "100M unités/an"}], "paragraphs": ["L''usine tourne actuellement à 62% de sa capacité installée en 1 poste — ce qui constitue le levier de croissance organique le plus immédiat. En passant à 2 postes, la capacité passe mécaniquement à 100M unités/an, soit +94% de capacité supplémentaire avec un investissement marginal (juste les coûts variables : MOD + énergie + matières)."]}}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'services';

  -- competition_market
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "valide_par": "K. N''Guessan (MD)", "version_note": "Section la plus consommatrice de knowledge_base et de web search. Sources : IFC Pharma Africa 2024, Directive UEMOA 2023, knowledge_benchmarks pharma UEMOA, web search avril 2026, entretien DG. C''est la section que l''analyste passait 3h sur Google à construire — ESONO l''a produite en 45 secondes à partir de 4 sources KB + 3 web searches.", "version_label": "IC1 (draft)"}, "footer": {"date": "il y a 2h", "sources": "IFC Pharma Africa 2024 (p.14-22, p.45-52), Directive UEMOA n°01/2023/CM, knowledge_benchmarks pharma UEMOA (panel 14 entreprises, score pertinence 0.95), web search avril 2026, entretien DG 08/04, entretien M. Diarra 11/04, knowledge_country_data CI + SN", "redige_par": "S. Koné", "review_par": "A. Diallo", "valide_par": "K. N''Guessan", "valide_date": "18 avr."}, "menaces": [{"body": "Un laboratoire indien (Cipla, Dr. Reddy''s) pourrait théoriquement décider de produire localement. Le marché UEMOA de 2.4 Mds USD est trop petit pour justifier l''investissement (5-10M USD pour une usine indienne vs 2-3M en local). Les multinationales préfèrent exporter depuis l''Inde (économies d''échelle). Aucun projet d''implantation identifié dans annonces publiques ou registres CEPICI.", "title": "Entrée d''un acteur international", "probability": "faible"}, {"body": "Abrogation de la Directive UEMOA 2023 supprimerait l''avantage 15%. Faible à moyen terme : adoption à l''unanimité des 8 États, tendance au renforcement (20-25%), pandémie a renforcé volonté souveraineté sanitaire. Même en cas d''abrogation, le moat BPF subsiste (importateurs ne peuvent toujours pas répondre aux AO certifiés).", "title": "Libéralisation préférence nationale", "probability": "faible"}, {"body": "L''UEMOA pourrait aligner ses normes BPF sur les standards WHO-PQ, plus exigeants. Probabilité modérée à 3-5 ans. Impact CAPEX 100-200M FCFA (équipements QC). Toucherait les 3 acteurs certifiés de la même manière — ne modifie pas le paysage relatif. PharmaCi a un avantage : Dr. Traoré certifié inspecteur BPF anticipe les évolutions.", "title": "Durcissement normes BPF (alignement OMS PQ)", "probability": "modérée"}, {"body": "Télémédecine, pharmacie digitale, production distribuée (imprimantes 3D) ? Très faible à 10 ans en UEMOA. Production de comprimés = processus industriel standardisé depuis 50 ans. Innovations (thérapies ciblées, biothérapies) concernent princeps, pas génériques. Télémédecine augmente la demande de médicaments — ne la réduit pas.", "title": "Substitution technologique", "probability": "très faible"}], "benchmark": {"rows": [{"ratio": "Marge brute", "median": "28%", "company": "32%", "quartile": "Q3"}, {"ratio": "Marge EBITDA", "median": "12%", "company": "15%", "quartile": "Q3"}, {"ratio": "EBITDA retraité", "median": "12%", "company": "10.6%", "quartile": "Q2"}, {"ratio": "BFR / CA", "median": "18%", "company": "17.4%", "quartile": "Q3↑"}, {"ratio": "Croiss. CA 3 ans", "median": "+10%", "company": "+18%", "quartile": "Q4"}], "source": "knowledge_benchmarks pharma UEMOA · IFC 2024 · 14 entreprises · score pertinence 0.95", "headers": ["PharmaCi", "Médiane", "Quartile"]}, "megatrends": [{"hint": "10M nouveaux consommateurs/an. Pop. UEMOA 140M (2025) → 180M (2035). Pyramide âges très jeune (médiane 18 ans).", "color": "ok", "label": "Croissance démographique UEMOA", "value": "+2.7%/an"}, {"hint": "Population urbaine consomme 3x plus de médicaments que rurale. Abidjan 6M hab. (+4%/an).", "label": "Urbanisation d''ici 2030", "value": "45% → 52%"}, {"hint": "CI : 38% → objectif 60% en 2030. SN : 47%. Chaque point CMU = ~280K personnes couvertes = demande additionnelle médicaments.", "color": "ok", "label": "Couverture maladie universelle", "value": "CMU"}], "concurrents": {"rows": [{"ca": "4.5", "pdm": "~18%", "cagr": "+6%", "name": "Pharmivoire", "marge": "35%", "analyse": "Leader historique 1987. Gamme la plus large (80+ réf.). Marge brute la plus élevée (mix spécialités). Croissance lente (+6% vs marché +10%), direction vieillissante (PDG 68 ans, pas de succession), pas d''expansion régionale. Coté BRVM mais liquidité très faible. Avantage : notoriété, historique. Faiblesse : inertie."}, {"ca": "2.8", "pdm": "~11%", "cagr": "+18%", "name": "PharmaCi", "marge": "32%", "analyse": "Challenger dynamique. Certification BPF 2019. Croissance la plus rapide du marché (2x médiane). DG entrepreneurial ex-Cipharm. Plan d''expansion Sénégal. Usine à 62% de capacité = marge de croissance embarquée. Avantage : dynamisme, capacité, expansion SN. Faiblesse : taille modeste, gouvernance centralisée.", "highlight": "self", "cagr_color": "ok"}, {"ca": "3.2", "pdm": "~13%", "cagr": "+9%", "name": "Cipharm", "marge": "28%", "analyse": "Filiale industrielle (actionnaire majoritaire non public). Stratégie volume : prix les plus bas, marges comprimées. Usine plus grande (~4 000 m²) mais ancienne (BPF sous conditions 2023). Pas de capacité d''expansion autonome (dépendance actionnaire). Avantage : volume, prix. Faiblesse : marges, gouvernance, pas d''agilité stratégique."}, {"ca": "1.8", "pdm": "~7%", "cagr": "+12%", "name": "Olea Medical (SN)", "marge": "30%", "analyse": "Sénégal uniquement. Spécialiste antipaludéens et antibiotiques. Certifié BPF SN. Concurrent direct potentiel pour expansion SN PharmaCi sur mêmes segments. Avantage : marché local SN, connaissance PSP Dakar. Faiblesse : gamme étroite, pas en CI."}, {"ca": "~15", "pdm": "~55%", "cagr": "+5%", "name": "Importateurs (panel)", "marge": "15-20%", "analyse": "~20 importateurs-distributeurs (Ubipharm, Laborex, COPHARMED + directs indiens). Pas de certification BPF → exclus AO publics. Concurrencent PharmaCi uniquement sur canal privé (pharmacies). Avantage : prix bas. Faiblesse : pas d''accès AO publics, délais longs."}], "intro": "Le marché ivoirien de la production locale de génériques est un oligopole réglementaire de fait : seuls 3 producteurs détiennent la certification BPF UEMOA (PharmaCi, Pharmivoire, Cipharm), plus une vingtaine d''importateurs-distributeurs non certifiés qui ne peuvent pas répondre aux AO publics hospitaliers. Un quatrième acteur (Pharma Ivoire Générique, fondé en 2020) a tenté la certification en 2022 mais a échoué — illustre la difficulté réelle de la barrière.", "dynamique": "PharmaCi gagne des parts de marché à un rythme de +1-2 points/an, principalement au détriment des importateurs sur les AO publics et de Cipharm sur les segments à marge plus favorable. Pharmivoire reste le leader incontesté mais sa croissance ralentit. À horizon 5-7 ans, PharmaCi a le potentiel de devenir le n°2 du marché devant Cipharm, avec un CA qui pourrait atteindre 5-6 Mds FCFA si le plan de croissance est exécuté."}, "tam_sam_som": {"sam": "Production locale de génériques certifiés BPF : 360-430M USD, 15-18% du TAM. Le reste est couvert par l''importation (Inde 55%, Chine 15%, Europe 12%, autres 3%). Segment protégé par certification BPF et Directive UEMOA 2023 — importateurs ne peuvent pas répondre aux AO publics hospitaliers (~40% du marché total en volume). Politique industrielle UEMOA vise 50% production locale d''ici 2030 (vs 18% actuellement).", "som": "Marché adressable PharmaCi estimé 80-120M USD : (a) AO hospitaliers CI 4 familles couvertes ~60M USD, (b) canal privé pharmacies CI mêmes familles ~30M USD, (c) AO hospitaliers SN expansion prévue ~20-30M USD. Exclut familles non couvertes (oncologie, antirétroviraux, vaccins). PDM actuelle ~11% du SAM et ~35% du SOM — place pour croître sans attaquer de nouveaux segments.", "tam": "Marché pharmaceutique total Afrique de l''Ouest : 2.4 milliards USD en 2025. Couvre l''ensemble des médicaments (princeps et génériques, importés et produits localement) dans les 8 pays UEMOA + adjacents CEDEAO. Croissance 8-10%/an depuis 2018, projection IFC 3.1 Mds USD d''ici 2028. Croissance structurelle portée par 3 mégatrends démographiques et sanitaires irréversibles."}, "positionnement": {"paragraphs": ["PharmaCi est le challenger le plus dynamique d''un oligopole réglementaire en croissance. Sa croissance (18% CAGR) est 2x la médiane. Sa marge brute (32%) supérieure au n°3 Cipharm (28%) et proche du leader Pharmivoire (35%). Son usine tourne à 62% — il a plus de marge de croissance que ses concurrents. Son DG est le plus entrepreneurial du secteur (ex-Cipharm, vision d''expansion régionale). Les menaces identifiées sont toutes à probabilité faible ou modérée, et aucune ne remet en cause le moat BPF.", "Le risque principal n''est pas la concurrence — c''est l''exécution. PharmaCi a le bon positionnement, le bon marché et le bon moat. Le risque est de ne pas exécuter le plan de croissance : retard nouvelle ligne, échec certification SN, non-recrutement DAF, dégradation gouvernance. Risques d''exécution, pas de marché — tous adressables avec l''investissement et la structuration prévue."]}, "reglementation": {"paragraphs": ["Directive UEMOA n°01/2023/CM — préférence nationale dans les marchés publics pharmaceutiques : adoptée mars 2023, entrée en vigueur janvier 2024. Avantage de 15% sur le prix d''évaluation aux producteurs locaux certifiés BPF dans les AO publics. Si producteur local soumissionne à 100 et importateur à 90, prix évaluation importateur reste 90 mais producteur local ajusté à 85 (100×0.85) → producteur local remporte l''AO malgré prix nominal plus élevé.", "Cette directive est le résultat de 5 ans de lobbying de l''APPAO (dont PharmaCi est membre) et de la pression des bailleurs (IFC, Proparco) qui conditionnent certains financements à la souveraineté sanitaire locale. Discussions en cours au Conseil des Ministres UEMOA pour renforcement à 20-25%, pas une libéralisation. Risque d''abrogation jugé faible — aucun État membre n''a intérêt à fragiliser ses producteurs locaux après COVID-19.", "Autres réglementations favorables : (1) Code des investissements CI 2018 — exonérations fiscales 5 ans pour entreprises industrielles pharmaceutiques (PharmaCi en a bénéficié 2019-2024). (2) Loi CMU-CI 2019 — chaque point couverture supplémentaire = ~280K personnes accédant au remboursement et donc à la consommation de génériques. (3) PNDIP 2022 — Programme National de Développement de l''Industrie Pharmaceutique CI : objectif 50% production locale d''ici 2030, subventions équipement, facilités douanières API."]}, "senegal_analysis": "Le marché pharma SN est plus petit que CI (~60% de la taille) mais en croissance plus rapide (+12%/an vs +10% en CI) grâce à un taux CMU plus élevé (47% vs 38%) et une politique de santé publique plus structurée. Le paysage concurrentiel comprend Olea Medical (certifié BPF SN, spécialiste antipaludéens — concurrent direct), West Africa Pharma (petit producteur, gamme limitée), et les mêmes importateurs qu''en CI. La certification BPF SN est distincte de CI mais le cadre UEMOA harmonise les exigences — le dossier PharmaCi peut être largement réutilisé. Délai estimé 6-12 mois (vs 18-24 pour première)."}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'competition_market';

  -- unit_economics
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "version_note": "Unit economics calculés à partir des inputs_history 2022-2025 et de l''entretien DG. Prix de vente et coûts unitaires = moyennes pondérées par le mix produit 2025. Marges par canal = estimations analytiques (non vérifié DD).", "version_label": "IC1 (draft)"}, "footer": {"date": "12 avr.", "sources": "inputs_history 2022-2025, entretien DG, analyse analyste, knowledge_benchmarks pharma UEMOA", "redige_par": "S. Koné"}, "benchmarks": {"rows": [["Marge contribution", "41 FCFA", "32 FCFA", {"v": "Q3", "color": "var(--pe-ok)"}, "Pharma UEMOA"], ["Coût API / coût total", "55%", "60%", {"v": "Q4", "color": "var(--pe-ok)"}, "IFC 2024"], ["Capacité utilisée", "62%", "70%", {"v": "Q2", "color": "var(--pe-warning)"}, "—"], ["Break-even / capacité", "36%", "45%", {"v": "Q4", "color": "var(--pe-ok)"}, "—"], ["Marge brute par SKU haut volume", "32%", "28%", {"v": "Q3", "color": "var(--pe-ok)"}, "Knowledge"]], "headers": ["Ratio", "PharmaCi", "Médiane", "Quartile", "Source"]}, "break_even": {"hint": "= 36% de la capacité installée · 1.7x la production actuelle", "value": "18M unités/an"}, "unit_eco_sn": "L''unit economics au Sénégal sera très proche de la CI : même fournisseurs API, même coûts excipients/conditionnement (légère hausse +2-3 FCFA pour le transport), même MOD (salaires comparables zone UEMOA). La différence vient des prix de vente : les AO PSP SN sont historiquement 5-10% plus élevés que les AO PSP CI (offre plus rare). Marge contribution SN estimée 43-45 FCFA vs 41 FCFA en CI.", "sensibilite_api": {"rows": [["Contrat cadre -5%", "30", "56", "43", {"v": "43%", "color": "var(--pe-ok)"}], ["Actuel", "32", "58", "41", "41%"], ["Hausse +10%", "35", "61", "38", {"v": "38%", "color": "var(--pe-warning)"}], ["Hausse +20%", "38", "64", "35", {"v": "35%", "color": "var(--pe-warning)"}]], "headers": ["Scénario", "Prix API", "Coût unit.", "Marge", "Marge %"]}, "rentabilite_canal": {"rows": [["AO public PSP", "85", "58", "27", {"v": "32%", "color": "var(--pe-warning)"}], ["Privé pharmacie", "120", "58", "62", {"v": "52%", "color": "var(--pe-ok)"}], ["Blended (mix 60/40)", "99", "58", "41", {"v": "41%", "bold": true, "color": "var(--pe-ok)"}]], "headers": ["Canal", "Prix moy. (FCFA)", "Coût unitaire", "Marge contribution", "Marge %"]}, "decomposition_cout": [{"hint": "55% du coût", "label": "API", "value": "32 FCFA"}, {"hint": "14%", "label": "Excipients", "value": "8 FCFA"}, {"hint": "9%", "label": "Conditionnement", "value": "5 FCFA"}, {"hint": "14%", "label": "MOD", "value": "8 FCFA"}, {"hint": "9%", "label": "Énergie", "value": "5 FCFA"}], "levier_operationnel": "Avec une marge contribution unitaire de 41 FCFA, chaque unité supplémentaire au-dessus du break-even génère 41 FCFA de bénéfice opérationnel. Pour passer de 31M unités (production 2025) à 50M (capacité 1 poste), le gain potentiel = 19M × 41 FCFA = 779M FCFA = +260% d''EBITDA.", "rentabilite_famille": {"rows": [["Antalgiques", "70", "49", "21", "30%"], ["Antibiotiques", "95", "63", "32", "34%"], ["Antipaludéens", "120", "77", "43", "36%"], ["Antihypert.", "115", "78", "37", "32%"]], "headers": ["Famille", "Prix moy.", "Coût", "Marge", "% CA"]}}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'unit_economics';

  -- financials_pnl
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "version_note": "Données issues des liasses SYSCOHADA 2023-2025. Liasses 2023 et 2024 non certifiées. Liasse 2025 certifiée par Cabinet Diallo & Associés avec réserves. Retraitements EBITDA = estimations analytiques à confirmer en DD.", "version_label": "IC1 (draft)"}, "footer": {"date": "13 avr.", "sources": "Liasses SYSCOHADA 2023-2025 (certifiées et non certifiées), rapport CAC 2025, inputs_history, relevés NSIA Banque, knowledge_benchmarks pharma UEMOA, quittances fiscales et CNPS", "redige_par": "S. Koné", "review_comment": "Bien documenté. Le taux effectif d''IS de 12% m''inquiète — demander une vérification complète des obligations fiscales en DD."}, "pnl_3y": {"rows": [{"bold": true, "delta": "+18% CAGR", "label": "Chiffre d''affaires net", "values": ["2 000", "2 400", "2 820"], "highlight": "ok"}, {"delta": "+22% CAGR", "label": "dont canal public (AO hospitaliers)", "indent": true, "values": ["1 140", "1 440", "1 692"], "highlight": "ok"}, {"delta": "+14% CAGR", "label": "dont canal privé (pharmacies)", "indent": true, "values": ["860", "960", "1 128"]}, {"delta": "+16%", "label": "Achats consommés (API + excipients + condit.)", "values": ["-1 420", "-1 656", "-1 918"]}, {"bold": true, "delta": "29% → 32%", "label": "Marge brute", "values": ["580", "744", "902"], "highlight": "ok"}, {"delta": "+23%", "label": "Charges de personnel", "values": ["-160", "-200", "-245"]}, {"sub": true, "delta": "méd. 12% ⚠", "label": "ratio masse salariale / CA", "values": ["8.0%", "8.3%", "8.7%"], "highlight": "warning"}, {"delta": "+18%", "label": "Autres charges d''exploitation", "values": ["-170", "-204", "-237"]}, {"bold": true, "delta": "12.5% → 14.9%", "label": "EBITDA déclaré", "values": ["250", "340", "420"]}, {"delta": "+22%", "label": "Dotations aux amortissements", "values": ["-80", "-100", "-120"]}, {"delta": "+33%", "label": "Résultat d''exploitation (EBIT)", "values": ["170", "240", "300"]}, {"delta": "Taux moy. 9.5%", "label": "Charges financières nettes", "values": ["-30", "-35", "-38"]}, {"delta": "Taux effectif ~12%", "label": "Impôt sur les sociétés (25%)", "values": ["-20", "-25", "-32"]}, {"bold": true, "delta": "+39%", "label": "Résultat net", "values": ["120", "180", "230"], "highlight": "ok"}, {"sub": true, "delta": "Expansion", "label": "Marge nette", "values": ["6.0%", "7.5%", "8.2%"], "highlight": "ok"}], "headers": ["2023", "2024", "2025"]}, "tax_rate": {"narrative": "Taux d''imposition effectif ~12% en 2025 vs taux nominal IS 25% en CI. Écart explicable par exonérations Code des investissements (2019-2024) et amortissements accélérés. Bénéfice exonérations expiré fin 2024 — taux effectif devrait se normaliser vers 20-25% à partir de 2026. Projections intègrent 22%. Point DD : vérifier absence d''arriérés fiscaux latents (patentes, TVA, CNPS) pendant la période d''exonération. Quittances 2024-2025 consultées sont à jour mais ne couvrent que l''IS."}, "synthesis": "PharmaCi affiche un profil de croissance exceptionnel (Q4 sur la croissance CA) avec des marges au-dessus de la médiane sur tous les ratios sauf l''EBITDA retraité (Q2 à 10.6%, sous la médiane de 12%). La masse salariale anormalement basse (8.7% vs 12%) est le signal du retraitement rémunération DG — pas un signe de productivité exceptionnelle mais un red flag comptable. Une fois le DG rémunéré au marché, la marge EBITDA devrait se normaliser dans la fourchette 10-13% selon le plan de croissance.", "benchmarks": {"rows": [{"p25": "24%", "ratio": "Marge brute", "median": "28%", "company": "32%", "quartile": "Q3", "highlight": "ok"}, {"p25": "8%", "ratio": "Marge EBITDA déclarée", "median": "12%", "company": "14.9%", "quartile": "Q3", "highlight": "ok"}, {"p25": "9%", "ratio": "Marge EBITDA retraitée", "median": "12%", "company": "10.6%", "quartile": "Q2", "highlight": "warning"}, {"p25": "6%", "ratio": "Croissance CA 3 ans", "median": "10%", "company": "18%", "quartile": "Q4", "highlight": "ok"}, {"p25": "4%", "ratio": "Marge nette", "median": "7%", "company": "8.2%", "quartile": "Q3", "highlight": "ok"}, {"p25": "10%", "ratio": "Masse salariale / CA", "median": "12%", "company": "8.7%", "quartile": "< P25 ⚠", "highlight": "danger"}], "source": "knowledge_benchmarks pharma UEMOA · Panel 14 entreprises 2023-2025 · Score pertinence 0.95 · Quartiles calculés par ESONO"}, "growth_analysis": {"paragraphs": ["18% CAGR sur 3 ans — la croissance la plus rapide du secteur. Le CA est passé de 2.0 Mds FCFA (2023) à 2.82 Mds (2025). Cette croissance est essentiellement portée par le canal public (+22% CAGR) qui a bénéficié de la montée en puissance des AO hospitaliers post-certification BPF (2019) et de l''entrée en vigueur de la Directive UEMOA 2023. Le canal privé croît plus lentement (+14% CAGR) car plafonné par la taille du réseau de distribution (120 pharmacies). La croissance n''est pas artificielle — elle est portée par du volume réel (nombre d''AO actifs : 4 → 12) et non par une hausse des prix (régulés par la PSP).", "Qualité de la croissance : pas de clients exceptionnels, pas de ventes ponctuelles, pas d''effet de base. Le CA 2023 (+15%) incluait les premiers AO post-Directive UEMOA. 2024 (+20%) reflétait l''accélération (8 → 11 AO actifs). 2025 (+17%) montrait une normalisation vers le rythme tendanciel de 15-18%. Confirmation à valider en DD par cartographie clients + analyse récurrence."]}, "ebitda_adjustments": {"note": "Note importante : dans le pre-screening initial, l''EBITDA retraité avait été estimé à 320M FCFA (retraitement DG uniquement). L''identification des charges personnelles additionnelles lors de la visite site a conduit à réviser à 300M (marge 10.6%). Cette révision place la marge sous la médiane sectorielle (12%) — réduit le score financier de 2 points. La marge reste au Q2 (entre P25 9% et P50 12%) et ne constitue pas un deal breaker.", "red_flags": [{"body": "Masse salariale 8.7% du CA en 2025 vs médiane sectorielle 12%. Écart 3.3 pts × 2.82 Mds = ~93M FCFA, cohérent avec rémun. DG non comptabilisée. DG n''apparaît pas sur fiches paie CNPS. En entretien : se rémunère par prélèvements sans montant fixe. Estimation analyste 80-120M FCFA/an. Hypothèse retenue : 100M (milieu fourchette, confiance moyenne). À confirmer DD par CAC.", "title": "Rémunération dirigeant non déclarée", "severity": "High"}, {"body": "CAC a signalé mélange perso/pro dans certif 2025. Visite site : Land Cruiser SCI Kouassi (~8M), frais déplacement non documentés (~10M), abonnements non identifiés (~5M). Estimation retenue 20M FCFA (confiance faible — montants individuels estimatifs).", "title": "Charges personnelles (confiance faible)", "severity": "Medium"}], "reconciliation": {"rows": [{"bold": true, "label": "EBITDA déclaré 2025", "value": "420"}, {"label": "(-) Retraitement rémunération DG estimée", "value": "-100", "highlight": "danger"}, {"label": "(-) Retraitement charges personnelles", "value": "-20", "highlight": "warning"}, {"bold": true, "label": "EBITDA retraité 2025", "value": "300", "highlight": "ok"}, {"label": "Marge EBITDA retraitée", "value": "10.6%", "highlight": "warning"}, {"label": "vs médiane sectorielle", "value": "12% (Q2)"}]}}, "gross_margin_analysis": {"paragraphs": ["La marge brute est passée de 29% (2023) à 32% (2025) — expansion de 3 points en 3 ans. Trois facteurs : (1) économies d''échelle achats — volume API +40% en 3 ans → meilleur pouvoir de négociation auprès des fournisseurs indiens ; (2) amélioration mix produit — antipaludéens (marge 36%) et antibiotiques (marge 34%) en hausse au détriment des antalgiques (marge 30%) ; (3) effet de levier sur coûts semi-fixes (salle blanche, énergie, QC).", "Positionnement vs benchmarks : 32% place PharmaCi au Q3 sectoriel (médiane 28%, P25 24%, P75 33%). Supérieur à Cipharm (28%, stratégie volume/prix bas), proche de Pharmivoire (35%, gamme spécialités à marge élevée). L''écart avec Pharmivoire s''explique par le mix produit — Pharmivoire a des molécules spécialisées (oncologie, endocrinologie) que PharmaCi ne produit pas."]}}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'financials_pnl';

  -- financials_balance
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "version_note": "Données issues des liasses SYSCOHADA 2023-2025 et des relevés bancaires NSIA (12 mois). Immobilisations en VNC — valeur de remplacement de l''usine estimée 600-800M FCFA. Créances en valeur brute, pas de provision créances douteuses identifiée.", "version_label": "IC1 (draft)"}, "footer": {"date": "14 avr.", "sources": "Liasses SYSCOHADA 2023-2025, relevés NSIA Banque 12 mois (2 comptes), quittances fiscales et CNPS, rapport CAC 2025", "redige_par": "S. Koné", "review_comment": "Le creux de trésorerie à 15M FCFA est préoccupant — demander les relevés bancaires sur 24 mois en DD pour vérifier la saisonnalité."}, "bfr_kpis": [{"hint": "17.4% du CA", "color": "warning", "label": "BFR 2025", "value": "490M"}, {"hint": "vs 30j contractuels", "color": "danger", "label": "Jours clients", "value": "46j"}, {"hint": "normatif · cible 60j", "label": "Jours stocks", "value": "32j"}, {"hint": "court — achats spot", "color": "warning", "label": "Jours fournisseurs", "value": "15j"}, {"hint": "PharmaCi : 17.4% ⚠", "label": "BFR / CA méd. secteur", "value": "12%"}], "bilan_actif": {"rows": [{"bold": true, "delta": "-21%", "label": "Immobilisations nettes", "values": ["480", "420", "380"], "highlight": "warning"}, {"delta": "Amort. linéaire", "label": "dont équipements production", "indent": true, "values": ["350", "300", "270"]}, {"delta": "Salle blanche BPF", "label": "dont agencements / installations", "indent": true, "values": ["100", "90", "80"]}, {"delta": "Dont Land Cruiser SCI ⚠", "label": "dont matériel roulant", "indent": true, "values": ["30", "30", "30"]}, {"bold": true, "delta": "+39%", "label": "Stocks", "values": ["180", "210", "250"], "highlight": "warning"}, {"delta": "1 mois de prod.", "label": "dont matières premières (API + excipients)", "indent": true, "values": ["120", "140", "170"]}, {"delta": "Stock tampon", "label": "dont produits finis", "indent": true, "values": ["60", "70", "80"]}, {"bold": true, "delta": "+29%", "label": "Créances clients", "values": ["280", "320", "360"], "highlight": "warning"}, {"delta": "80% des créances ⚠", "label": "dont créances PSP (AO publics)", "indent": true, "values": ["200", "260", "290"], "highlight": "warning"}, {"delta": "Paiement 15-30j", "label": "dont créances grossistes (privé)", "indent": true, "values": ["80", "60", "70"]}, {"delta": "+55%", "label": "Autres actifs courants", "values": ["110", "130", "170"]}, {"delta": "Volatile", "label": "Trésorerie", "values": ["50", "70", "40"], "highlight": "warning"}, {"bold": true, "delta": "+9%", "label": "TOTAL ACTIF", "values": ["1 100", "1 150", "1 200"]}], "headers": ["2023", "2024", "2025"]}, "endettement": "La dette financière totale est de 320M FCFA (prêt MLT NSIA 220M + facilité de caisse 100M). Le prêt MLT est remboursé à 12M FCFA/mois et arrive à échéance en 2028. La facilité de caisse (100M, renouvelée annuellement à 9.5%) est utilisée pour couvrir les besoins de trésorerie courants liés aux retards de paiement PSP. La dette est exclusivement bancaire — pas d''endettement informel identifié (pas de tontines, pas de prêts familiaux, pas de prêts intercompany avec la SCI Kouassi, pas de retards CNPS ou fiscaux). C''est un signal très positif — l''endettement informel est le risque caché n°1 dans les PME UEMOA.", "leviers_bfr": {"intro": "Leviers de réduction du BFR identifiés :", "items": [{"n": 1, "body": "NSIA Banque propose un programme d''affacturage pour les créances publiques à un coût de 3-4% de la face value. Sur les 290M FCFA de créances PSP, cela permettrait de récupérer ~280M FCFA immédiatement contre un coût de 8-12M FCFA/an. Net positif si le coût de portage du BFR > coût de l''affacturage (c''est le cas car la facilité de caisse coûte 9.5%).", "title": "Affacturage des créances PSP"}, {"n": 2, "body": "Augmenter la part du canal privé (paiement 15-30j) de 40% à 50% du CA réduirait mécaniquement les jours clients blended de 46j à ~38j.", "title": "Extension du canal privé"}, {"n": 3, "body": "Les contrats annuels permettent de négocier des délais de paiement de 30-45 jours (vs 15j au spot), augmentant les jours fournisseurs.", "title": "Contrats cadre fournisseurs API"}, {"n": 4, "body": "Paradoxalement, l''augmentation du stock de 1 à 2 mois (prévue dans le use of proceeds) augmente le BFR à court terme mais réduit le risque de rupture qui pourrait coûter un AO entier.", "title": "Stock tampon API"}]}, "bfr_analysis": {"paragraphs": ["Le BFR est en hausse continue depuis 3 ans (14.0% du CA en 2023, 15.8% en 2024, 17.4% en 2025). Cette dégradation est principalement causée par l''allongement des délais de paiement des AO publics hospitaliers : le délai contractuel avec la PSP est de 30 jours, mais le délai effectif est passé de 60 jours (2023) à 90-120 jours (2025). Les créances PSP représentent 290M FCFA en 2025, soit 80% des créances clients totales, dont 90M FCFA en retard de plus de 90 jours. C''est un problème systémique du secteur — les retards de paiement de la PSP touchent tous les fournisseurs — mais l''impact est proportionnellement plus fort sur PharmaCi car le canal public représente 60% du CA (vs médiane 50%)."]}, "bilan_passif": {"rows": [{"bold": true, "delta": "+71%", "label": "Capitaux propres", "values": ["420", "560", "720"], "highlight": "ok"}, {"delta": "Stable", "label": "dont capital social", "indent": true, "values": ["100", "100", "100"]}, {"delta": "Rétention profits", "label": "dont réserves + report à nouveau", "indent": true, "values": ["200", "280", "390"], "highlight": "ok"}, {"delta": "+92%", "label": "dont résultat de l''exercice", "indent": true, "values": ["120", "180", "230"], "highlight": "ok"}, {"bold": true, "delta": "-27%", "label": "Dettes financières MLT", "values": ["300", "260", "220"], "highlight": "ok"}, {"delta": "Taux 9.5% · Éch. 2028", "label": "prêt MLT NSIA Banque (remb. 12M/mois)", "indent": true, "values": ["300", "260", "220"]}, {"delta": "Renouvelée annuellement", "label": "Facilité de caisse NSIA", "values": ["150", "120", "100"]}, {"delta": "-25%", "label": "Dettes fournisseurs", "values": ["160", "140", "120"], "highlight": "ok"}, {"delta": "-43%", "label": "Autres passifs courants (fiscal, social)", "values": ["70", "70", "40"]}, {"bold": true, "delta": "Équilibré ✓", "label": "TOTAL PASSIF", "values": ["1 100", "1 150", "1 200"]}], "headers": ["2023", "2024", "2025"]}, "desendettement": "Le ratio dette nette / EBITDA est passé de 1.6x (2023) à 0.88x (2025). Cette trajectoire est portée par la combinaison du remboursement du prêt MLT (-80M sur 2 ans) et de la croissance de l''EBITDA (+170M sur 2 ans). Le profil de bilan est sain avec une capacité d''emprunt résiduelle significative (~680M FCFA si la cible D/E est maintenue sous 1.5x). Cette capacité pourrait être mobilisée pour du co-financement bancaire complémentaire au ticket PE (dette subordonnée ou prêt d''investissement NSIA pour la nouvelle ligne).", "vna_paragraphe": "Les capitaux propres de 720M FCFA (2025) représentent la valeur comptable de l''entreprise. La valorisation pre-money de 10-14M EUR (6.5-9.2 Mds FCFA) représente un multiple de 9-13x les capitaux propres — justifié par la croissance (18% CAGR), le moat BPF, et la capacité de production sous-utilisée. Le goodwill implicite (différence entre valorisation et VNA) est de ~90% — ratio cohérent avec les transactions PE mid-market pharma en Afrique.", "endettement_kpis": [{"hint": "vs seuil 2x · très sain", "color": "ok", "label": "Dette nette / EBITDA", "value": "0.88x"}, {"hint": "vs seuil 1.5x", "label": "Gearing (D/E)", "value": "0.44x"}, {"hint": "Trajectoire positive", "color": "ok", "label": "Désendettement 3 ans", "value": "1.6x → 0.88x"}, {"hint": "si cible D/E < 1.5x", "label": "Capacité d''emprunt résiduelle", "value": "~680M"}], "vigilance_points": [{"body": "(14% → 17.4% du CA) — principalement créances PSP. Levier : affacturage + extension canal privé. Cible post-investissement : <14%.", "title": "BFR en hausse continue"}, {"body": "(minimum 15M FCFA vs seuil confort 55M). L''injection de capital (15% BFR du use of proceeds = 0.63M EUR = ~413M FCFA) résout ce problème immédiatement. Post-closing, trésorerie confortée à 3-4 mois de charges fixes.", "title": "Trésorerie volatile avec creux dangereux"}], "bfr_decomposition": {"rows": [{"label": "(+) Stocks", "comment": "+39%. Stock API insuffisant (1 mois)", "value_a": "180", "value_b": "250"}, {"bold": true, "label": "(+) Créances clients", "comment": "+29%. PSP 290M dont 90M >90j ⚠", "value_a": "280", "value_b": "360", "highlight": "warning"}, {"label": "(-) Dettes fournisseurs", "comment": "-25%. Achats spot = paiement rapide", "value_a": "-160", "value_b": "-120"}, {"bold": true, "label": "BFR", "comment": "+63% en 2 ans", "value_a": "300", "value_b": "490", "highlight": "danger"}, {"label": "BFR / CA", "comment": "vs médiane 12%", "value_a": "15.0%", "value_b": "17.4%"}], "headers": ["2023", "2025", "Commentaire"]}, "tresorerie_analysis": "La trésorerie est volatile : 50M (2023) → 70M (2024) → 40M (2025). La baisse en 2025 s''explique par l''allongement des délais PSP combiné à la croissance du CA public (plus de volume = plus de créances en attente). Les relevés NSIA montrent des creux de trésorerie récurrents en fin de trimestre (avril, juillet, octobre) lorsque les paiements PSP sont en retard simultané sur plusieurs AO. Le solde minimum observé sur 12 mois est de 15M FCFA (février 2025) — dangereux car en dessous du seuil de confort de 1 mois de charges fixes (~55M FCFA).", "cash_flow_operations": "Malgré la tension sur le BFR, le cash flow opérationnel est positif sur les 3 exercices. En 2025, il est estimé à ~180M FCFA (résultat net 230M + D&A 120M - variation BFR -170M). L''investissement CAPEX de maintenance est de ~30M FCFA/an. Le free cash flow résiduel (~150M FCFA) est utilisé pour le remboursement du prêt MLT (144M/an) — il ne reste quasiment rien pour la trésorerie. C''est pourquoi le financement par equity est le bon instrument : PharmaCi n''a pas la capacité de service de dette additionnelle significative sans l''injection de capital.", "no_red_flag_conclusion": "Aucun red flag financier majeur détecté sur le bilan. Pas de dettes cachées, pas d''endettement informel, pas d''arriérés fiscaux ou CNPS (quittances à jour), pas de provisions pour risques non identifiées, pas de surévaluation d''actifs évidente. Profil PME industrielle saine en phase de croissance avec un BFR tendu par les délais publics — un profil classique en UEMOA."}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'financials_balance';

  -- investment_thesis
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"pivot_hint": "Section pivot — c''est celle que le MD lit en premier après le résumé. Elle doit convaincre en 3 paragraphes maximum.", "redige_par": "S. Koné", "review_par": "A. Diallo (IM)", "valide_par": "K. N''Guessan (MD)", "version_note": "Pré-due diligence. Données [non vérifié DD] à confirmer par DD externe.", "version_label": "IC1 (draft)"}, "footer": {"date": "14 avr.", "sources": "deliverables.valuation, organization_knowledge (thèse fonds Adiwale), AVCA 2024, knowledge_risk_params", "redige_par": "S. Koné", "review_par": "A. Diallo (IM)", "valide_par": "K. N''Guessan (MD)", "review_date": "17 avr.", "valide_date": "18 avr."}, "thesis_match": {"total": 6, "criteria": [{"label": "Secteur cible", "status": "match"}, {"label": "Ticket dans la fourchette", "status": "match"}, {"label": "Géographie éligible", "status": "match"}, {"label": "CA minimum requis", "status": "match"}, {"label": "États financiers certifiés", "status": "partial"}, {"label": "EBITDA positif exigé", "status": "match"}], "match_count": 5, "score_percent": 83}, "exit_strategy": {"narratif": "Trade sale (acquéreur pharma régional Pharmivoire ou industriel indien Cipla/Dr. Reddy''s cherchant base production UEMOA) est le scénario le plus probable. Le secondaire (revente fonds plus gros AfricInvest, Cauris Croissance II) est le plan B. L''IPO BRVM est envisageable à horizon 7 ans si CA dépasse 10 Mds FCFA — PharmaCi serait alors le premier producteur pharma indépendant coté en zone UEMOA. [analyse analyste · AVCA Exit Report 2024 · BRVM conditions admission]"}, "structuration": {"ticket": {"hint": "Augmentation de capital", "value": "4-6M EUR"}, "horizon": {"hint": "Extension possible", "value": "5-7 ans"}, "pre_money": {"hint": "8-10x EBITDA retraité", "value": "10-14M EUR"}, "participation": {"hint": "Minoritaire", "value": "25-35%"}, "instrument_note": "Type d''instrument : augmentation de capital en equity pure. Le fondateur ne souhaite pas de dette mezzanine — il veut un partenaire stratégique, pas un créancier. Pas de preferred shares ni de waterfall complex à ce stade.", "governance_items": ["Un siège au CA pour l''investisseur (le fonds)", "Un administrateur indépendant (Dr. Aka, ex-DG Pharmivoire ou M. Ouédraogo, PDG Sitab CI)", "Droit de veto investisseur sur : CAPEX > 100M FCFA, endettement > 1x EBITDA, cession actifs significatifs, rémunération DG > 20M FCFA/trim, modification statuts", "Reporting trimestriel standardisé (format ESONO automatisé)", "Clause tag-along / drag-along standard AUSCGIE", "Droit de première offre en cas de cession par le fondateur"]}, "five_arguments": {"items": [{"n": 1, "body": "Certification BPF UEMOA = 200-400M FCFA, 18-24 mois. Seuls 3 producteurs en CI la détiennent. La 2e couche : 42 agréments par molécule accumulés sur 12 ans. Un concurrent certifié devrait attendre 3-5 ans pour atteindre la même couverture. La 3e couche : AO publics exigent historique fourniture 2+ ans. La Directive UEMOA 2023 (+15% prix AO) ajoute une couche réglementaire. Discussions en cours pour renforcement à 20-25%. Moat auto-renforçant et résistant aux disruptions tech. [§4, §5 · Directive UEMOA n°01/2023/CM]", "lead": "Un moat réglementaire durable, cumulatif et auto-renforçant."}, {"n": 2, "body": "CAGR CA 18% sur 3 ans, la plus rapide du secteur pharma CI. 3 leviers cumulatifs : (a) capacité existante 62%→100% = +38% sans CAPEX, (b) nouvelle ligne x2 capacité, (c) expansion SN. Pipeline 8 AO en cours dont 3 quasi-certains. Investissement 100% orienté croissance — 85% CAPEX productif. [§4, §7 · inputs_history · devis Sejong]", "lead": "Une croissance visible, diversifiable et finançable."}, {"n": 3, "body": "Demande médicaments essentiels insensible aux cycles. Impact direct quantifiable : ODD 3 (2M+ patients/an), ODD 8 (127+30 emplois), ODD 9 (production locale substitutive). Profil recherché par DFI (Proparco, BII, IFC) qui co-investissent avec PE africains. [§11]", "lead": "Un secteur défensif, contra-cyclique et à impact mesurable."}, {"n": 4, "body": "DCF EV 12.4M EUR (WACC 18.5%, g 3%). Multiples comparables 11.8M EUR (médiane 8.2x EV/EBITDA — Pharmivoire, Cipharm, Strides). Écart 5% renforce robustesse fourchette 10-14M EUR pre-money. Bear MOIC 1.8x/IRR 12% (au-dessus seuil fonds 1.5x). Base 2.8x/22% (au-dessus médiane PE mid-market Afrique 2.5x). Bull 4.1x/33%. Sensibilité : même WACC 20.5% + g 1.5% = valo 9.1M EUR au-dessus du ticket. [valuation ESONO · knowledge_risk_params]", "lead": "Un rendement attractif avec protection du capital dans tous les scénarios."}, {"n": 5, "body": "M. Kouassi (72%, DG) : 14 ans pharma dont 3 chez Cipharm. Ne cherche pas exit — veut accélérer. Management pool 10% aligne 3 cadres clés. Fondateur a validé en entretien les 6 conditions de structuration sans résistance — coopération proactive rare dans PME familiales UEMOA. Réduit le risque d''exécution post-closing. [§2, §3 · entretien DG 08/04]", "lead": "Un management fondateur aligné, compétent et coopératif."}]}, "scenarios_returns": {"base": {"irr": "22%", "moic": "2.8x", "tagline": "exécution du plan à 80%", "description": "Croissance CA 15%/an (nouvelle ligne opérationnelle, expansion SN partielle 3/5 AO). Exit 8x EBITDA via trade sale ou secondaire (AfricInvest, Cauris Croissance). Valorisation sortie ~32M EUR. Gain net 7.6M EUR. Au-dessus de la médiane PE mid-market Afrique (MOIC 2.5x AVCA 2024)."}, "bear": {"irr": "12%", "moic": "1.8x", "tagline": "marché stagne, pas d''expansion SN", "description": "Croissance CA 8%/an (ligne existante uniquement). Exit 6x EBITDA via trade sale à un industriel régional (Pharmivoire ou Cipharm). Valorisation sortie ~18M EUR. Gain net 3.2M EUR sur ticket 4.2M. Capital protégé — fonds récupère 1.8x sa mise même dans le pire cas."}, "bull": {"irr": "33%", "moic": "4.1x", "tagline": "expansion régionale réussie", "description": "Croissance CA 22%/an (nouvelle ligne pleine capacité + SN + début BF). Exit 10x EBITDA (prime croissance 22% CAGR). Sortie possible IPO BRVM si CA > 10 Mds FCFA (plausible 7 ans) ou secondaire premium fonds panafricain. Valorisation ~50M EUR."}, "pre_money_indicatif": "10-14M EUR"}}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'investment_thesis';

  -- support_requested
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "version_note": "Pré-due diligence. Données à confirmer DD.", "version_label": "IC1 (draft)"}, "footer": {"date": "14 avr.", "sources": "Business plan, pitch deck, entretien DG, devis Sejong Pharmatech, organization_knowledge (méthodologie Adiwale post-investissement)", "redige_par": "S. Koné"}, "kpis_suivi": {"rows": [{"m6": "3.0", "t0": "2.82", "kpi": "Chiffre d''affaires (Mds FCFA)", "m12": "3.5+", "m12_color": "ok"}, {"m6": "11.5%", "t0": "10.6%", "kpi": "Marge EBITDA retraitée", "m12": "13%+", "m12_color": "ok"}, {"m6": "70%", "t0": "62%", "kpi": "Taux utilisation capacité", "m12": "80%+", "m12_color": "ok"}, {"m6": "55%", "t0": "62%", "kpi": "Concentration client top 3", "m12": "<50%", "t0_color": "danger", "m12_color": "ok"}, {"m6": "16%", "t0": "17.4%", "kpi": "BFR / CA", "m12": "<14%", "t0_color": "warning", "m12_color": "ok"}, {"m6": "14", "t0": "12", "kpi": "Nombre d''AO actifs (CI + SN)", "m12": "18+", "m12_color": "ok"}, {"m6": "135", "t0": "127", "kpi": "Effectifs (CDI)", "m12": "155+"}, {"m6": "7/7", "t0": "0/7", "kpi": "Checklist gouvernance (/7)", "m12": "7/7", "m6_color": "ok", "t0_color": "danger", "m12_color": "ok"}]}, "decaissement": "Tranche 1 (70% = 2.94M EUR) au closing. Tranche 2 (30% = 1.26M EUR) conditionnée à la réalisation des 6 points de structuration 100 jours (CA formalisé + DAF recruté + AG régularisées + comptes séparés + double signature + assurance homme-clé). Si la tranche 2 n''est pas déclenchée dans les 6 mois → clause de renégociation ou de sortie anticipée (put option).", "summary_note": "85% du ticket orienté CAPEX productif. L''investissement est entièrement orienté vers la croissance — pas de remboursement de dette (désendettement naturel en cours : D/EBITDA 1.6x → 0.88x), pas de cash-out fondateur, pas de restructuration défensive. Profil que les fonds PE mid-market industriel recherchent — chaque euro investi génère directement de la capacité de production et du CA additionnel.", "valeur_ajoutee": "Au-delà du capital, le fonds apporte : (1) un réseau de recrutement pour les postes clés (DAF, DRH, Dir. SN), (2) une méthodologie de structuration de la gouvernance rodée sur 15+ participations en portefeuille, (3) un accès privilégié aux DFI (Proparco, BII) pour du co-investissement ou de la dette subordonnée complémentaire, (4) un réseau d''acquéreurs potentiels pour la sortie (book de contacts industriels pharma régionaux + fonds secondaires).", "value_creation_plan": [{"items": [{"body": "Poste inexistant, priorité absolue. Profil et budget en §3. Mandat cabinet recrutement spécialisé dès J+1. Conditionne tout le reste — sans DAF, pas de reporting fiable, pas de contrôle des flux, pas de séparation comptes.", "delay": "semaines 1-8", "title": "Recrutement DAF"}, {"body": "DG (M. Kouassi) + 1 représentant investisseur + 1 admin indépendant. 2 profils identifiés : Dr. Aka (ex-DG Pharmivoire) et M. Ouédraogo (PDG Sitab CI). Budget 5M FCFA.", "delay": "semaines 2-4", "title": "Formalisation CA 3 membres"}, {"body": "Production des PV manquants. Mise en conformité article 337 AUSCGIE.", "delay": "semaines 2-6", "title": "Régularisation AG 2024-2025"}, {"body": "Ouverture compte professionnel dédié NSIA. Basculement flux commerciaux. Clôture carte bancaire personnelle utilisée pour achats entreprise.", "delay": "semaines 1-4", "title": "Séparation comptes perso/pro"}, {"body": "Tout engagement > 5M FCFA nécessite signature conjointe DG + DAF.", "delay": "dès recrutement DAF", "title": "Double signature bancaire"}, {"body": "Police sur M. Kouassi et Dr. Traoré (les deux hommes-clés). Budget 5-8M FCFA/an.", "delay": "semaines 4-8", "title": "Assurance homme-clé"}], "horizon": "H1", "budget_note": "Budget total 100 jours : ~25M FCFA (DAF prorata + frais juridiques + assurance). Milestone décaissement : tranche 2 (30% du ticket = 1.26M EUR) conditionnée à la réalisation des 6 points."}, {"items": [{"body": "Acompte 40% (1.01M EUR). Délai livraison 6-8 mois. Installation 4-6 semaines. Qualification 2-4 semaines. Ligne opérationnelle M+9 à M+12.", "delay": "mois 2", "title": "Commande nouvelle ligne Sejong Pharmatech"}, {"body": "127 employés sans politique RH formalisée. Budget 10M FCFA/an. Premières actions : grille salariale, entretiens annuels, plan de formation BPF.", "delay": "mois 3-4", "title": "Recrutement DRH"}, {"body": "Dépôt dossier autorité régulation SN. Première inspection M+6 à M+9. M. Diarra pilote en attendant Dir. pays.", "delay": "mois 3-6", "title": "Certification BPF Sénégal"}, {"body": "Passage achats spot → contrats annuels Cipla, Dr. Reddy''s, Aurobindo. Objectif -5% prix API = +45M FCFA/an de marge sur volume actuel. Engagement volume minimum en contrepartie.", "delay": "mois 2-4", "title": "Contrats cadre fournisseurs API"}, {"body": "Recrutement 2 commerciaux terrain. Extension 120 → 200 pharmacies. Budget 8M FCFA/an. Impact CA estimé +200M FCFA/an à pleine charge.", "delay": "mois 3-6", "title": "Extension réseau privé"}], "horizon": "H2", "budget_note": "Budget cumulé 6 mois : ~2.5M EUR (acompte Sejong + recrutements + certif SN + BFR)"}, {"items": [{"body": "Capacité totale portée à 100M unités/an en 2 postes. Premiers lots commerciaux produits sur la nouvelle ligne.", "delay": "M+9 à M+12", "title": "Nouvelle ligne opérationnelle et qualifiée"}, {"body": "5 AO hospitaliers ciblés (PSP Dakar). Taux conversion attendu 40-60% (2-3 AO gagnés). CA SN prévisionnel année 1 : 300-500M FCFA.", "delay": "M+12", "title": "Première réponse AO Sénégal"}, {"body": "Pharmacien industriel avec réseau hospitalier SN. Budget 15-20M FCFA/an. Basé à Dakar.", "delay": "M+10-12", "title": "Recrutement Dir. pays Sénégal"}, {"body": "Premier reporting complet par DAF au format ESONO (automatisé). Dashboard monitoring activé avec alertes sur les 6 KPIs.", "delay": "M+12", "title": "Reporting trimestriel opérationnel"}, {"body": "CA ≥ 3.5 Mds FCFA (+25% vs N-1) · EBITDA retraité ≥ 13% (vs 10.6%) · Capacité > 80% · Concentration < 50% · BFR/CA < 14% · Gouvernance 7/7", "delay": "", "title": "Cibles M+12"}], "horizon": "H3", "budget_note": "Budget total 12 mois : ~4.2M EUR (100% du ticket). Solde tranche 2 libéré après validation des 6 conditions de structuration."}], "use_of_proceeds_detailed": [{"body": "2.52M EUR · Sejong Pharmatech (Corée du Sud) · +50M unités/an · Détail technique en §4 · Délai commande→qualification : 9-12 mois", "label": "Nouvelle ligne de production", "percent": 60, "highlight": true}, {"body": "1.05M EUR · Bureau Dakar + Dir. pays (15-20M FCFA/an) + Dossier certification BPF SN (6-12 mois) + 5 premiers AO ciblés · M. Diarra (ex-Sanofi, réseau SN) assure l''intérim", "label": "Expansion Sénégal", "percent": 25, "highlight": true}, {"body": "0.63M EUR · Stock tampon API (2 mois vs 1 mois actuel — buffer tensions logistiques mer Rouge) + Exploration affacturage créances PSP", "label": "Fonds de roulement", "percent": 15}]}'::jsonb
    WHERE version_id IN (v_pre_v, v_ic1_v) AND section_code = 'support_requested';

  -- esg_risks
  UPDATE memo_sections SET content_md = NULL, content_json = '{"meta": {"redige_par": "S. Koné (Analyste)", "review_par": "A. Diallo (IM)", "valide_par": "K. N''Guessan (MD)", "version_note": "L''analyse ESG est basée sur la visite site du 11/04, l''entretien DG, les documents sociaux (CNPS, contrats), et le cadre IFC Performance Standards. Évaluation E&S externe nécessaire en DD pour les DFI co-investisseurs.", "version_label": "IC1 (draft)"}, "footer": {"date": "15 avr.", "sources": "Visite site 11/04, quittances CNPS 2024-2025, contrats de travail, IFC PS framework, IRIS+ metrics (GIIN), 2X Criteria IFC, knowledge_risk_factors (12 SYSCOHADA), Proparco Stratégie 2025, BII Investment Portfolio", "redige_par": "S. Koné", "review_par": "A. Diallo (IM)", "valide_par": "K. N''Guessan (MD)", "review_date": "17 avr.", "valide_date": "18 avr."}, "ifc_ps": {"rows": [{"ps": "1", "analyse": "Aucun SGES formalisé. Pas de politique E&S, pas de responsable, pas de gestion des plaintes. Action : SGES dans les 6 mois post-closing. Budget 15M FCFA.", "standard": "Système de gestion E&S", "conformite": "Non conforme", "conformite_color": "danger"}, {"ps": "2", "analyse": "Points + : CDI à jour 127 employés, CNPS à jour, convention collective pharma CI, pas de travail enfants. Points à améliorer : grille salariale, entretiens annuels, comité hygiène/sécurité (obligatoire >50 emp.), gestion plaintes.", "standard": "Conditions de travail", "conformite": "Conforme partiel", "conformite_color": "ok"}, {"ps": "3", "analyse": "Déchets pharma 620 kg/an (200 kg dangereux). Traitement par SITRADE CI mais pas de bordereau de suivi. Action : incinérateur agréé (20-30M) ou contrat formalisé. Énergie 72 MWh/an, eau 500 m³/an conformes.", "standard": "Utilisation efficiente des ressources", "conformite": "Partiel", "conformite_color": "warning"}, {"ps": "4", "analyse": "Zone industrielle Cosrou Yopougon, pas de communauté résidentielle adjacente. Pas de risque contamination. Produits = médicaments certifiés BPF.", "standard": "Santé et sécurité communautaires", "conformite": "Non applicable", "conformite_color": "ok"}, {"ps": "5", "analyse": "Usine en location (bail SCI Kouassi). Pas d''acquisition prévue. Nouvelle ligne dans usine existante. Expansion SN = bureau location Dakar.", "standard": "Acquisition de terres et réinstallation", "conformite": "Non applicable", "conformite_color": "ok"}, {"ps": "6", "analyse": "Zone industrielle urbaine. Pas d''habitat naturel ni biodiversité sensible.", "standard": "Conservation de la biodiversité", "conformite": "Non applicable", "conformite_color": "ok"}, {"ps": "7", "analyse": "Zone urbaine Abidjan. Pas de peuples autochtones affectés.", "standard": "Peuples autochtones", "conformite": "Non applicable", "conformite_color": "ok"}, {"ps": "8", "analyse": "Zone industrielle. Pas de patrimoine culturel identifié.", "standard": "Patrimoine culturel", "conformite": "Non applicable", "conformite_color": "ok"}], "intro": "Évaluation préliminaire — une évaluation E&S formelle par consultant externe (ERM, Mott MacDonald, ou cabinet local agréé IFC) sera nécessaire en DD si un DFI co-investit. Budget estimé : 15-25M FCFA pour évaluation E&S complète.", "synthesis": "Sur les 3 PS applicables (PS1, PS2, PS3), PharmaCi est non conforme PS1 (pas de SGES) et partiellement conforme PS2/PS3. Toutes corrigeables post-investissement (~50-65M FCFA : SGES 15M + incinérateur 25M + politique RH 10M + évaluation E&S 15M). Mise en conformité = prérequis si DFI co-investit (12 mois post-closing)."}, "odd_kpis": [{"hint": "2M+ patients/an via AO hospitaliers publics", "color": "ok", "label": "ODD 3 — Bonne santé et bien-être", "value": "Direct"}, {"hint": "127 emplois industriels +30 post-invest. · Convention pharma CI", "label": "ODD 8 — Travail décent et croissance", "value": "Direct"}, {"hint": "Production locale · Substitution imports · Souveraineté sanitaire", "label": "ODD 9 — Industrie, innovation, infra.", "value": "Direct"}, {"hint": "Éligible si structuration genre post-investissement", "color": "warning", "label": "2X Criteria IFC", "value": "Potentiel"}], "iris_plus": {"note": "Les indicateurs IRIS+ seront formalisés dans le pacte d''actionnaires avec cibles contractuelles et reporting semestriel. Le DG a exprimé son accord de principe.", "rows": [{"cible": "4M+", "actuel": "2M+", "method": "Volume AO × posologie moyenne. Source : données PSP.", "indicator": "PI4060 — Clients desservis"}, {"cible": "157", "actuel": "127", "method": "Registre CNPS. Vérifiable trimestriellement.", "indicator": "OI1638 — Emplois à plein temps"}, {"cible": "30%", "actuel": "18%", "method": "CNPS. Actuel : 23 femmes / 127 (admin et QC).", "indicator": "OI5765 — Emplois femmes (%)", "actuel_color": "warning"}, {"cible": "50M+", "actuel": "31M", "method": "Comptabilité production. Traçabilité lot par lot.", "indicator": "PI2822 — Unités vendues"}, {"cible": "4.5 Mds", "actuel": "2.82 Mds", "method": "Liasses SYSCOHADA certifiées.", "indicator": "PI1279 — Revenus nets"}, {"cible": "40h/an", "actuel": "n/d", "method": "À formaliser post-investissement.", "indicator": "OI3160 — Formation employés (h)", "actuel_color": "warning"}]}, "odd_details": {"odd3": "ODD 3 — Accès aux médicaments essentiels : impact le plus direct et mesurable de PharmaCi. Génériques produits localement distribués via AO hospitaliers PSP à des prix 30-40% inférieurs aux princeps importés et 10-15% inférieurs aux génériques importés (hors bonus Directive UEMOA). Chaque AO = 200K-500K patients traités/an. Avec 12 AO actifs : 2M+ patients/an. L''expansion SN (5 AO ciblés) doublerait à 3-4M patients/an.", "odd8": "ODD 8 — Emploi industriel décent : 127 personnes en CDI (70% production, 30% admin/cadres) + 25 saisonniers. Masse salariale 245M FCFA/an. Ouvriers formés BPF — compétence rare et transférable en Afrique de l''Ouest. Plan post-invest : +30 emplois (cf. §3 et §10). L''emploi pharma valorisé par les DFI car compétences durables dans secteur stratégique pour la souveraineté sanitaire africaine.", "odd9": "ODD 9 — Production locale et substitution aux imports : PharmaCi contribue à la politique industrielle UEMOA (objectif 50% production locale d''ici 2030, vs 18% actuel). Chaque unité produite localement = 1 unité importée en moins. Vulnérabilité démontrée pendant COVID-19 (approvisionnements indiens interrompus 3 mois). Capacité 50M → 100M unités/an renforce la souveraineté sanitaire CI et UEMOA."}, "risks_matrix": {"rows": [{"prob": "Moy.", "title": "1. Concentration client >70%", "impact": "Critique", "mitigation": "DEAL BREAKER si confirmé en DD. Actuel 62% top 3 (estimation). Les 3 clients sont AO hospitaliers PSP récurrents. Cartographie détaillée en DD. Si >70% → Hold.", "prob_color": "warning", "title_color": "danger", "impact_color": "danger"}, {"prob": "Moy.", "title": "2. Hausse prix API (+15-20%)", "impact": "Élevé", "mitigation": "Hausse 12% en 2024 (mer Rouge). +20% → marge brute 41→35% (au-dessus médiane). Contrats cadre annuels (-5%), 4ème fournisseur (Strides), stock 2 mois.", "prob_color": "warning", "title_color": "warning", "impact_color": "warning"}, {"prob": "Moy.", "title": "3. Homme-clé DG", "impact": "Élevé", "mitigation": "Cumul 4 fonctions (cf. §3). Recrutement DAF 100j (cf. §10), assurance homme-clé, plan succession.", "prob_color": "warning", "title_color": "warning", "impact_color": "warning"}, {"prob": "Faible", "title": "4. Homme-clé Dr. Traoré", "impact": "Élevé", "mitigation": "Seul pharmacien certifié inspecteur BPF. Assurance homme-clé, formation adjoint QC 12 mois.", "title_color": "ok", "impact_color": "warning"}, {"prob": "Moy.", "title": "5. Retard certification BPF SN", "impact": "Modéré", "mitigation": "Délai 6-12 mois extensible 18 mois. Projections n''intègrent pas CA SN avant 2028 — 6 mois retard ne change pas le base case. Dossier CI réutilisable.", "prob_color": "warning", "title_color": "ok"}, {"prob": "Faible", "title": "6. Libéralisation préférence nationale", "impact": "Élevé", "mitigation": "Suppression bonus 15% UEMOA improbable (tendance inverse 20-25%). Moat BPF subsiste — importateurs ne peuvent répondre AO. Impact estimé -10-15% CA public.", "title_color": "ok", "impact_color": "warning"}, {"prob": "Faible", "title": "7. Risque pays CI", "impact": "Modéré", "mitigation": "Stabilité macro (PIB +6.5%, Ba3, inflation 3.8%). Élection 2025 sans incident. CRP 4.8% intégré WACC. Diversification SN.", "title_color": "ok"}, {"prob": "Faible", "title": "8. Risque de change (FCFA/USD)", "impact": "Modéré", "mitigation": "FCFA arrimé EUR (parité fixe). Exposition indirecte via API USD. EUR/USD gérable. Pas de couverture (coût prohibitif PME).", "title_color": "ok"}]}, "two_x_criteria": {"rows": [{"post": "Non", "actuel": "Non", "analyse": "Mme Kouassi détient 18% mais pas de rôle opérationnel. Le DG (72%) est un homme.", "criterion": "1. Entrepreneuriat (>51% femmes au capital)", "post_status": "danger", "actuel_status": "danger"}, {"post": "Potentiel", "actuel": "Non", "analyse": "Pas de CA actuel. Post-invest : si admin indépendant est une femme (Dr. Coulibaly identifiée) → 1/3 = 33% ✓.", "criterion": "2. Leadership (>30% femmes au CA ou C-suite)", "post_status": "warning", "actuel_status": "danger"}, {"post": "Potentiel", "actuel": "Partiel", "analyse": "18% femmes (23/127). Seuil 30%. Plan : recrutement genré sur 30 nouveaux postes. Si 60% féminins → 35% ✓.", "criterion": "3. Emploi (>30-50% femmes employées)", "post_status": "warning", "actuel_status": "warning"}, {"post": "Oui", "actuel": "Oui", "analyse": "Médicaments essentiels bénéficient aux femmes de manière disproportionnée (santé maternelle, pédiatrie). Critère rempli ✓.", "criterion": "4. Consommation (produits/services bénéficiant aux femmes)", "post_status": "ok", "actuel_status": "ok"}, {"post": "N/A", "actuel": "N/A", "analyse": "Non applicable — investissement direct.", "criterion": "5. Investissement via intermédiaires", "post_status": "ok", "actuel_status": "ok"}], "intro": "Les 2X Criteria de l''IFC mesurent l''engagement genre sur 5 dimensions. PharmaCi est éligible sur 1/5 actuellement et potentiellement sur 2/5 post-structuration :", "conclusion": "PharmaCi est éligible sur le critère 4 (consommation) de facto. L''éligibilité sur les critères 2 et 3 est atteignable post-structuration. Levier important pour attirer les DFI co-investisseurs (Proparco, BII, FMO) qui ont des mandats genre."}, "dfi_attractivite": {"dfis": [{"name": "Proparco (FR)", "note": "Priorité santé Afrique. Co-invest. régulier avec PE mid-market (Adiwale, I&P). Mandat 2X. Relation existante.", "ticket": "1-3M EUR", "instrument": "Equity ou dette sub."}, {"name": "BII (UK)", "note": "Portefeuille santé Afrique en croissance. Co-invest. directe aux côtés des fonds. Exigence IFC PS rigoureuse.", "ticket": "1-5M EUR", "instrument": "Equity directe"}, {"name": "IFC (Banque mondiale)", "note": "Programme IFC SME Ventures pharma locale Afrique. Ticket min 3M USD — PharmaCi limite basse.", "ticket": "2-5M EUR", "instrument": "Equity ou dette sub."}, {"name": "FMO (NL)", "note": "Actif en pharma Afrique. Préfère dette subordonnée. Pourrait financer la nouvelle ligne en dette à côté de l''equity PE.", "ticket": "2-5M EUR", "instrument": "Dette sub."}], "intro": "PharmaCi coche toutes les cases des mandats DFI Afrique : (1) santé (ODD 3, priorité n°1 des DFI subsahariennes 25-30% portefeuilles Proparco/BII), (2) production industrielle locale (ODD 9, souveraineté post-COVID), (3) emploi décent industriel (ODD 8, plus valorisé que services), (4) ticket compatible co-investissement (1-2M EUR en dette sub. ou equity), (5) potentiel 2X Criteria (objectifs genre 30-50% portefeuille DFI)."}, "red_flags_syscohada": {"rows": [{"bold": true, "color": "danger", "factor": "1. Concentration client (62% top 3)", "status": "ACTIF", "penalty": "-15 pts", "severity": "Critical"}, {"bold": true, "color": "danger", "factor": "2. EBITDA sans rémunération dirigeant", "status": "ACTIF", "penalty": "-8 pts", "severity": "High"}, {"bold": true, "color": "danger", "factor": "3. Gouvernance centralisée", "status": "ACTIF", "penalty": "-5 pts", "severity": "High"}, {"color": "warning", "factor": "4. BFR en hausse (17.4% du CA)", "status": "Monitorer", "penalty": "-0", "severity": "Medium"}, {"color": "warning", "factor": "5. Convention réglementée bail SCI Kouassi", "status": "Monitorer", "penalty": "-0", "severity": "Medium"}, {"color": "ok", "factor": "6. Cash non tracé / flux informels", "status": "Non détecté", "penalty": "0", "severity": "—"}, {"color": "ok", "factor": "7. Dettes fournisseurs anormales", "status": "Non détecté", "penalty": "0", "severity": "—"}, {"color": "ok", "factor": "8. Endettement informel", "status": "Non détecté", "penalty": "0", "severity": "—"}, {"color": "ok", "factor": "9. Croissance artificielle / ventes ponctuelles", "status": "Non détecté", "penalty": "0", "severity": "—"}, {"color": "warning", "factor": "10. Charges personnelles dans compte exploitation", "status": "Détecté partiel", "penalty": "-0", "severity": "Medium"}, {"color": "ok", "factor": "11. Arriérés fiscaux / CNPS", "status": "Non détecté", "penalty": "0", "severity": "—"}, {"color": "ok", "factor": "12. Sous-capitalisation", "status": "Non détecté", "penalty": "0", "severity": "—"}], "score_net": 74, "threshold": 65, "score_brut": 97}}'::jsonb
